noncompliant:
void DoSomething(int someParameter, string anotherParam)
{
    if (someParameter < 0)
    {
        throw new ArgumentException("Bad argument", "someParameter"); // Noncompliant - hardcoded parameter name
    }
    if (anotherParam == null)
    {
        throw new Exception("anotherParam should not be null"); // Noncompliant
    }
}

compliant:
void DoSomething(int someParameter, string anotherParam)
{
    if (someParameter < 0)
    {
        throw new ArgumentException("Bad argument", nameof(someParameter)); // Compliant
    }
    if (anotherParam == null)
    {
        throw new Exception($"{nameof(anotherParam)} should not be null"); // Compliant
    }
}
